import React, { useEffect, useRef, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import Footer from './Footer'; // ✅ ADDED

/* ─── Reveal Hook ───────────────── */
function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const obs = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          obs.disconnect();
        }
      },
      { threshold: 0.15 }
    );

    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return [ref, visible];
}

/* ─── Reveal Wrapper ───────────── */
function Reveal({ children, delay = 0 }) {
  const [ref, visible] = useReveal();

  return (
    <div
      ref={ref}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(30px)',
        transition: `all 0.7s cubic-bezier(.22,1,.36,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

/* ─── Counter ─────────────────── */
function Counter({ to }) {
  const [count, setCount] = useState(0);
  const [ref, visible] = useReveal();

  useEffect(() => {
    if (!visible) return;

    let start = 0;
    const step = Math.ceil(to / 50);

    const t = setInterval(() => {
      start += step;
      if (start >= to) {
        setCount(to);
        clearInterval(t);
      } else setCount(start);
    }, 20);

    return () => clearInterval(t);
  }, [visible, to]);

  return <span ref={ref}>{count}+</span>;
}

/* ─── Main Component ──────────── */
export default function Home() {
  const { user } = useAuth();
  const navigate = useNavigate();

  const dashboards = {
    student: '/student',
    company: '/company',
    admin: '/admin',
  };

  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const features = [
    { icon: '💼', title: 'Smart Job Matching', desc: 'AI-powered match score for every job.' },
    { icon: '📚', title: 'Learning Hub', desc: 'Courses + certificates to boost your skills.' },
    { icon: '🧠', title: 'AI Career Advisor', desc: 'Personalized guidance and career insights.' },
    { icon: '🗺️', title: 'Career Roadmap', desc: 'Step-by-step path to your dream job.' },
    { icon: '🏆', title: 'Certificates', desc: 'Earn and showcase your achievements.' },
    { icon: '📊', title: 'Analytics', desc: 'Companies get powerful hiring insights.' },
  ];

  return (
    <div style={{ background: 'var(--bg-base)', color: 'var(--text-primary)' }}>

      {/* NAV */}
      <nav
        style={{
          position: 'fixed',
          top: 0,
          width: '100%',
          height: 70,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '0 40px',
          backdropFilter: 'blur(18px)',
          background: scrolled
            ? 'rgba(10,12,22,0.85)'
            : 'rgba(10,12,22,0.5)',
          borderBottom: scrolled
            ? '1px solid rgba(255,255,255,0.05)'
            : 'transparent',
          zIndex: 999,
          transition: 'all .3s ease',
        }}
      >
        <Link to="/" style={{ fontWeight: 800 }}>StudentBridge</Link>

        <div style={{ display: 'flex', gap: 20 }}>
          <Link to="/about">About</Link>
          <Link to="/contact">Contact</Link>

          {user ? (
            <button
              onClick={() => navigate(dashboards[user.role])}
              className="btn btn-primary"
            >
              Dashboard
            </button>
          ) : (
            <>
              <Link to="/login">Sign In</Link>
              <Link to="/register" className="btn btn-primary">
                Get Started
              </Link>
            </>
          )}
        </div>
      </nav>

      {/* HERO */}
      <section style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '120px 40px 60px', position: 'relative' }}>
        <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(circle at 30% 20%, rgba(79,142,247,0.15), transparent 60%)' }} />

        <div style={{ maxWidth: 1100, textAlign: 'center', zIndex: 1 }}>
          <Reveal>
            <h1 style={{ fontSize: '3rem', fontWeight: 800 }}>
              Bridge the Gap Between <span style={{ color: 'var(--accent-primary)' }}>Talent</span> and Opportunity
            </h1>
          </Reveal>

          <Reveal delay={0.2}>
            <p style={{ marginTop: 20, color: 'var(--text-secondary)' }}>
              AI-powered job matching, career guidance, and learning tools — all in one platform.
            </p>
          </Reveal>
        </div>
      </section>

      {/* FEATURES */}
      <section style={{ padding: '80px 40px' }}>
        <div style={{ maxWidth: 1100, margin: '0 auto' }}>
          <h2 style={{ textAlign: 'center', marginBottom: 40 }}>Everything You Need</h2>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 20 }}>
            {features.map((f, i) => (
              <Reveal key={i} delay={i * 0.1}>
                <div
                  style={{
                    padding: 24,
                    borderRadius: 16,
                    background: 'var(--bg-card)',
                    border: '1px solid var(--border)',
                    transition: '0.3s',
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.transform = 'translateY(-6px) scale(1.02)';
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.transform = 'translateY(0) scale(1)';
                  }}
                >
                  <div style={{ fontSize: 28 }}>{f.icon}</div>
                  <h3>{f.title}</h3>
                  <p>{f.desc}</p>
                </div>
              </Reveal>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section style={{ padding: 80, textAlign: 'center' }}>
        <h2>Ready to Start?</h2>
        <p>Join StudentBridge today</p>

        <Link to="/register" className="btn btn-primary">
          Get Started
        </Link>
      </section>

      {/* FOOTER */}
      <Footer />
    </div>
  );
}
